// // This module implements a synchronous reset D flip-flop using a 2-input LUT. It has a single output 'q' that is always set to 1 when 'rst' is active.
module sync_reset_dff (
  input clk,
  input rst,
  input d,
  output reg q
);

  always @(posedge clk, negedge rst) begin
    if (~rst) begin
      q <= 1'b0;
    end else begin
      q <= d;
    end
  end

endmodule
